query:
SELECT c.id as clienteId, c.nomeCompleto, v.id as veiculoId, v.placa, v.modelo
FROM `07_clientes` c
JOIN `08_veiculos` v ON v.clienteId = c.id
WHERE c.nomeCompleto = 'Carlos Eduardo Mendes'
LIMIT 1;

SELECT id, nome, cargo FROM `01_colaboradores` WHERE cargo LIKE '%Consultor%' AND ativo = 1 LIMIT 5;

SELECT id, nome, grauConhecimento FROM `03_mecanicos` WHERE ativo = 1 LIMIT 5;

